import AppKit
import Foundation

struct ScreenEvent: Codable {
    enum Kind: String, Codable {
        case on, off
        case screensaverOn, screensaverOff

        /// True when this event means user is away from screen
        var isAway: Bool { self == .off || self == .screensaverOn }
    }
    let kind: Kind
    let time: Date
}

