185	    // MARK: - Project Entries
186	
187	    func recordProjectEntry(_ project: String) {
188	        var data = loadData()
189	        data.projectEntries.append(ProjectEntry(project: project, time: Date()))
190	        saveData(data)
191	        scheduleProjectTimer()
192	    }
193	
194	    // MARK: - Time Calculation
195	
196	    func totalOnTime(events: [ScreenEvent]) -> TimeInterval {
197	        var total: TimeInterval = 0
198	        var lastOn: Date?
199	
200	        for event in events {
201	            if event.kind == .on || event.kind == .screensaverOff {
202	                if lastOn == nil { lastOn = event.time }  // don't overwrite — keep earliest start
203	            } else if event.kind.isAway, let on = lastOn {
204	                total += event.time.timeIntervalSince(on)
205	                lastOn = nil
206	            }
207	        }
208	        if let on = lastOn { total += Date().timeIntervalSince(on) }
209	        return total
210	    }
211	
212	    /// Worked time = sum of span durations minus break-attributed time within each span.
213	    /// This counts project-attributed offline time (meetings etc.) as worked, unlike raw screen-on time.
214	    func workedTime(spans: [TimeSpan], allEntries: [ProjectEntry], firstOnTime: Date?) -> TimeInterval {
215	        spans.reduce(0.0) { total, span in
216	            let spanEnd = span.end ?? Date()
217	            let spanDur = spanEnd.timeIntervalSince(span.start)
218	            let d = computeProjectDurations(allEntries: allEntries, firstOnTime: firstOnTime,
219	                                            spanStart: span.start, spanEnd: spanEnd)
220	            let breakDur = d.first(where: { $0.project == "Break" })?.duration ?? 0
221	            return total + max(0, spanDur - breakDur)
222	        }
223	    }
224	
225	    struct TimeSpan {
226	        let start: Date
227	        let end: Date?   // nil = still active
228	        let isActive: Bool
229	    }
230	
231	    func buildTimeSpans(from events: [ScreenEvent],
232	                        projectEntries: [ProjectEntry] = [],
233	                        mergeThreshold: TimeInterval = 3 * 60) -> [TimeSpan] {
234	        // Build raw completed spans
235	        var rawSpans: [(start: Date, end: Date)] = []
236	        var spanStart: Date? = nil
237	
238	        for event in events {
239	            switch event.kind {
240	            case .on, .screensaverOff:
241	                if spanStart == nil { spanStart = event.time }
242	            case .off, .screensaverOn:
243	                if let s = spanStart {
244	                    rawSpans.append((start: s, end: event.time))
245	                    spanStart = nil
246	                }
247	            }
248	        }
249	        let activeStart = spanStart  // non-nil if screen still on
250	
251	        // Gap covered by a project (not Break) = spans should be merged regardless of duration.
252	        // The first entry at or after gapEnd tells us what the user was doing during the gap.
253	        func gapCoveredByWork(gapEnd: Date) -> Bool {
254	            guard let first = projectEntries.first(where: { $0.time >= gapEnd }) else { return false }
255	            return first.project != "Break"
256	        }
257	
258	        // Merge completed spans whose gap is < threshold OR covered by non-Break project
259	        var merged: [(start: Date, end: Date)] = []
260	        for span in rawSpans {
261	            if let last = merged.last {
262	                let gap = span.start.timeIntervalSince(last.end)
263	                if gap < mergeThreshold || gapCoveredByWork(gapEnd: span.start) {
264	                    merged[merged.count - 1] = (start: last.start, end: span.end)
265	                    continue
266	                }
267	            }
268	            merged.append(span)
269	        }
270	
271	        // Attach or append active span
272	        var result = merged.map { TimeSpan(start: $0.start, end: $0.end, isActive: false) }
273	        if let active = activeStart {
274	            if let last = merged.last {
275	                let gap = active.timeIntervalSince(last.end)
276	                if gap < mergeThreshold || gapCoveredByWork(gapEnd: active) {
277	                    result[result.count - 1] = TimeSpan(start: last.start, end: nil, isActive: true)
278	                } else {
279	                    result.append(TimeSpan(start: active, end: nil, isActive: true))
280	                }
281	            } else {
282	                result.append(TimeSpan(start: active, end: nil, isActive: true))
283	            }
284	        }
285	        return result
286	    }
287	
288	    /// For each project whose entry falls inside [spanStart, spanEnd], compute how much
289	    /// time within that span is attributed to it.
290	    ///
291	    /// Attribution rule: entry[i] claims the interval [entry[i-1].time, entry[i].time]
292	    /// (or [firstOnTime, entry[0].time] for the first entry of the day).
293	    /// The last entry additionally claims [entry.last.time, spanEnd] (still working on it).
294	    /// Each claim is intersected with [spanStart, spanEnd].
295	    func computeProjectDurations(
296	        allEntries: [ProjectEntry],
297	        firstOnTime: Date?,
298	        spanStart: Date,
299	        spanEnd: Date
300	    ) -> [(project: String, duration: TimeInterval)] {
301	        guard !allEntries.isEmpty else { return [] }
302	
303	        let dayStart = firstOnTime ?? allEntries[0].time
304	        var durations: [String: TimeInterval] = [:]
305	
306	        for i in 0..<allEntries.count {
307	            let entry = allEntries[i]
308	            let claimStart = i == 0 ? dayStart : allEntries[i - 1].time
309	            let intStart = max(claimStart, spanStart)
310	            let intEnd   = min(entry.time, spanEnd)
311	            if intEnd > intStart {
312	                durations[entry.project, default: 0] += intEnd.timeIntervalSince(intStart)
313	            }
314	        }
315	
316	        // Last entry also claims forwards to spanEnd
317	        if let last = allEntries.last {
318	            let intStart = max(last.time, spanStart)
319	            if spanEnd > intStart {
320	                durations[last.project, default: 0] += spanEnd.timeIntervalSince(intStart)
321	            }
322	        }
323	
324	        return durations
325	            .map { (project: $0.key, duration: $0.value) }
326	            .filter { $0.duration >= 30 }
327	            .sorted { $0.duration > $1.duration }
328	    }
