330	    /// Same pairing logic as totalOnTime — must stay in sync.
331	    func screenOnIntervals(from events: [ScreenEvent]) -> [(start: Date, end: Date)] {
332	        var intervals: [(start: Date, end: Date)] = []
333	        var lastOn: Date?
334	        for event in events {
335	            if event.kind == .on || event.kind == .screensaverOff {
336	                lastOn = event.time
337	            } else if event.kind.isAway, let on = lastOn {
338	                intervals.append((on, event.time))
339	                lastOn = nil
340	            }
341	        }
342	        if let on = lastOn { intervals.append((on, Date())) }
343	        return intervals
344	    }
