350	        guard !allEntries.isEmpty else { return 0 }
351	        let dayStart = firstOnTime ?? allEntries[0].time
352	
353	        func intersect(_ claimStart: Date, _ claimEnd: Date) -> TimeInterval {
354	            onIntervals.reduce(0) { sum, iv in
355	                let s = max(claimStart, iv.start), e = min(claimEnd, iv.end)
356	                return e > s ? sum + e.timeIntervalSince(s) : sum
357	            }
358	        }
359	
360	        var total: TimeInterval = 0
361	        for i in 0..<allEntries.count {
