363	            let claimStart = i == 0 ? dayStart : allEntries[i - 1].time
364	            total += intersect(claimStart, allEntries[i].time)
365	        }
366	        if allEntries.last?.project == "Break" {
367	            total += intersect(allEntries.last!.time, Date())
