struct TimeSpan { let start: Date; let end: Date?; let isActive: Bool }

func buildTimeSpans(from events: [ScreenEvent], projectEntries: [ProjectEntry] = [],
                    mergeThreshold: TimeInterval = 3*60, now: Date) -> [TimeSpan] {
    var rawSpans: [(Date, Date)] = []; var spanStart: Date? = nil
    for e in events {
        switch e.kind {
        case .on, .screensaverOff: if spanStart == nil { spanStart = e.time }
        case .off, .screensaverOn: if let s = spanStart { rawSpans.append((s, e.time)); spanStart = nil }
        }
    }
    let activeStart = spanStart
    func gapCoveredByWork(gapEnd: Date) -> Bool {
        guard let f = projectEntries.first(where: { $0.time >= gapEnd }) else { return false }
        return f.project != "Break"
    }
    var merged: [(Date, Date)] = []
    for span in rawSpans {
        if let last = merged.last, (span.0.timeIntervalSince(last.1) < mergeThreshold || gapCoveredByWork(gapEnd: span.0)) {
            merged[merged.count-1] = (last.0, span.1)
        } else { merged.append(span) }
    }
    var result = merged.map { TimeSpan(start: $0.0, end: $0.1, isActive: false) }
    if let active = activeStart {
        if let last = merged.last, (active.timeIntervalSince(last.1) < mergeThreshold || gapCoveredByWork(gapEnd: active)) {
            result[result.count-1] = TimeSpan(start: last.0, end: nil, isActive: true)
        } else { result.append(TimeSpan(start: active, end: nil, isActive: true)) }
    }
    return result
}

func computeProjectDurations(allEntries: [ProjectEntry], firstOnTime: Date?,
                              spanStart: Date, spanEnd: Date) -> [(project: String, duration: TimeInterval)] {
    guard !allEntries.isEmpty else { return [] }
    let dayStart = firstOnTime ?? allEntries[0].time
    var d: [String: TimeInterval] = [:]
    for i in 0..<allEntries.count {
        let e = allEntries[i]; let cs = i == 0 ? dayStart : allEntries[i-1].time
        let s = max(cs, spanStart); let e2 = min(e.time, spanEnd)
        if e2 > s { d[e.project, default: 0] += e2.timeIntervalSince(s) }
    }
    if let last = allEntries.last {
        let s = max(last.time, spanStart)
        if spanEnd > s { d[last.project, default: 0] += spanEnd.timeIntervalSince(s) }
    }
    return d.map{(project:$0.key,duration:$0.value)}.filter{$0.duration>=30}.sorted{$0.duration>$1.duration}
}

